import{_ as i,c as a,o as r,ah as n}from"./chunks/framework.C-x9UAyH.js";const m=JSON.parse('{"title":"Creación de un ACR","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"azure/creacion_acr.md","filePath":"azure/creacion_acr.md","lastUpdated":1760551994000}'),c={name:"azure/creacion_acr.md"};function o(l,e,d,u,t,p){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="creacion-de-un-acr" tabindex="-1">Creación de un ACR <a class="header-anchor" href="#creacion-de-un-acr" aria-label="Permalink to &quot;Creación de un ACR&quot;">​</a></h1><h2 id="validacion-de-maquina-virtual-creada-y-grupo-de-recursos-en-azure-portal" tabindex="-1">Validación de máquina virtual creada y grupo de recursos en Azure Portal <a class="header-anchor" href="#validacion-de-maquina-virtual-creada-y-grupo-de-recursos-en-azure-portal" aria-label="Permalink to &quot;Validación de máquina virtual creada y grupo de recursos en Azure Portal&quot;">​</a></h2><ol><li>Validar que se esté ejecutando la máquina virtual en Azure Portal</li><li>Si no está en ejecución se debe desplegar nuevamente a través del pipeline de despliegue de infraestructura</li><li>Confirmar la IP pública de la máquina virtual</li><li>Contar con un grupo de recursos creado, ideal mismo donde reside la máquina virtual.</li></ol><h2 id="creacion-de-imagen-docker-y-subir-a-acr" tabindex="-1">Creación de imagen Docker y subir a ACR <a class="header-anchor" href="#creacion-de-imagen-docker-y-subir-a-acr" aria-label="Permalink to &quot;Creación de imagen Docker y subir a ACR&quot;">​</a></h2><ol><li><p>Creación de Registro de contenedor (ACR).</p></li><li><p>Creación de imagen Docker (Dockerfile) “ej. Imagen nginx” y sus archivos de configuración default.conf y index.html.</p></li><li><p>Creación de código pipeline en yaml para subir imagen Dockerfile a ACR.</p></li><li><p>Subir archivos a GitHub: Dockerfile, default.conf, index.html en una estructura de directorio.</p></li><li><p>Subir archivo código pipeline a GitHub para subir imagen Dockerfile hacia ACR.</p></li><li><p>Crear Service Connections Docker Registry de tipo Azure Container Registry.</p></li><li><p>Creación y Ejecución de Azure Pipeline con código YAML desde repositorio GitHub para subir imagen Dockerfile.</p></li><li><p>Evidencias de la ejecución del pipeline en Azure Portal sección Registros de contenedor y validar que este la imagen subida.</p></li></ol><h2 id="preparar-ambiente-y-ejecucion-del-pipeline" tabindex="-1">Preparar ambiente y ejecución del Pipeline <a class="header-anchor" href="#preparar-ambiente-y-ejecucion-del-pipeline" aria-label="Permalink to &quot;Preparar ambiente y ejecución del Pipeline&quot;">​</a></h2><ol><li>Crear Service Connections con Azure Resource Manager y el grupo de recurso.</li><li>Crear un entorno en Azure pipeline para registrar la máquina virtual y dar permisos al repositorio pipeline.</li><li>Creación de código pipeline en yaml para instalar Docker, azure cli y hacer pull y run de imagen en ACR.</li><li>Subir archivo código pipeline a GitHub para posterior ejecución en Azure Pipeline.</li><li>Creación y Ejecución de Azure Pipeline con código YAML desde repositorio GitHub para instalar y ejecutar Docker con la imagen nginx y página de bienvenida.</li><li>Revisión de la ejecución del job del pipeline.</li><li>Ejecutar IP publica de la máquina virtual en navegador web.</li><li>Evidencias de la ejecución del pipeline desde máquina virtual como ejecución de Docker ps.</li></ol><h3 id="instrucciones-para-configuracion-y-optimizacion-de-contenedores" tabindex="-1">Instrucciones para Configuración y Optimización de Contenedores <a class="header-anchor" href="#instrucciones-para-configuracion-y-optimizacion-de-contenedores" aria-label="Permalink to &quot;Instrucciones para Configuración y Optimización de Contenedores&quot;">​</a></h3><p>Consulta esta guía: <a href="https://drive.google.com/file/d/1yh1iA30x4eDQad0yutha0ApkOH9fK6VI/view?usp=drive_link" target="_blank">Máquina Virtual y ACR</a></p>',9)])])}const g=i(c,[["render",o]]);export{m as __pageData,g as default};
